    {{ getScriptDisplayName(script) }}\n          </h4>\n          <div class=\"script-meta\">\n            <span class=\"script-status\" :class=\"{ enabled: script.enabled }\">\n              {{ getScriptStatusText(script) }}\n            </span>\n            <span v-if=\"script.buttons.length > 0\" class=\"script-buttons-count\">\n              <i class=\"fa-solid fa-mouse-pointer\"></i>\n              {{ script.buttons.length }}\n            </span>\n          </div>\n        </div>\n\n        <!-- 操作按钮 -->\n        <div class=\"script-actions\">\n          <button\n            @click.stop=\"$emit('toggle', script.id)\"\n            :class=\"['toggle-btn', { enabled: script.enabled }]\"\n            :title=\"script.enabled ? '禁用脚本' : '启用脚本'\"\n          >\n            <i :class=\"script.enabled ? 'fa-solid fa-toggle-on' : 'fa-solid fa-toggle-off'\"></i>\n          </button>\n\n          <button\n            @click.stop=\"$emit('run', script.id)\"\n            class=\"action-btn run-btn\"\n            title=\"运行脚本\"\n            :disabled=\"!script.enabled\"\n          >\n            <i class=\"fa-solid fa-play\"></i>\n          </button>\n\n          <button @click.stop=\"$emit('menu', script, $event)\" class=\"action-btn menu-btn\" title=\"更多操作\">\n            <i class=\"fa-solid fa-ellipsis-v\"></i>\n          </button>\n        </div>\n      </div>\n\n      <!-- 脚本描述 -->\n      <div v-if=\"script.info\" class=\"script-description\">\n        {{ script.info }}\n      </div>\n\n      <!-- 脚本内容预览 -->\n      <div v-if=\"showContentPreview\" class=\"script-preview\">\n        <div class=\"preview-header\">\n          <span class=\"preview-label\">代码预览</span>\n          <button @click.stop=\"showContentPreview = false\" class=\"preview-close-btn\">\n            <i class=\"fa-solid fa-times\"></i>\n          </button>\n        </div>\n        <pre class=\"preview-code\">{{ getContentPreview(script.content) }}</pre>\n      </div>\n\n      <!-- 展开/收缩按钮 -->\n      <div v-if=\"script.content && !showContentPreview\" class=\"script-footer\">\n        <button @click.stop=\"showContentPreview = true\" class=\"expand-btn\" title=\"查看代码预览\">\n          <i class=\"fa-solid fa-code\"></i>\n          查看代码\n        </button>\n      </div>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { ref } from 'vue';\nimport type { Script } from '../schemas/script.schema';\n\n// Props\ninterface Props {\n  script: Script;\n  isSelected: boolean;\n}\n\ndefineProps<Props>();\n\n// Emits\ninterface Emits {\n  select: [id: string];\n  toggle: [id: string];\n  run: [id: string];\n  menu: [script: Script, event: Event];\n}\n\ndefineEmits<Emits>();\n\n// Local state\nconst showContentPreview = ref(false);\n\n// Methods\n/**\n * 获取脚本显示名称\n */\nconst getScriptDisplayName = (script: Script): string => {\n  return script.name.trim() || '未命名脚本';\n};\n\n/**\n * 获取脚本状态文本\n */\nconst getScriptStatusText = (script: Script): string => {\n  return script.enabled ? '已启用' : '已禁用';\n};\n\n/**\n * 获取内容预览\n */\nconst getContentPreview = (content: string): string => {\n  const lines = content.split('\\n');\n  const maxLines = 10;\n  const previewLines = lines.slice(0, maxLines);\n\n  if (lines.length > maxLines) {\n    previewLines.push('...');\n  }\n\n  return previewLines.join('\\n');\n};\n</script>\n\n<style scoped>\n.script-item {\n  background: var(--SmartThemeBlurTintColor);\n  border: 1px solid var(--SmartThemeBorderColor);\n  border-radius: 6px;\n  padding: 12px;\n  cursor: pointer;\n  transition: all 0.2s ease;\n}\n\n.script-item:hover {\n  background: var(--SmartThemeEmColor);\n  border-color: var(--SmartThemeQuoteColor);\n}\n\n.script-item.selected {\n  background: var(--SmartThemeQuoteColor);\n  border-color: var(--SmartThemeEmColor);\n}\n\n.script-item.disabled {\n  opacity: 0.6;\n}\n\n.script-item-content {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n\n.script-header {\n  display: flex;\n  justify-content: space-between;\n  align-items: flex-start;\n  gap: 12px;\n}\n\n.script-info {\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n  flex: 1;\n  min-width: 0; /* 防止文字溢出 */\n}\n\n.script-name {\n  margin: 0;\n  font-size: 14px;\n  font-weight: 600;\n  color: var(--SmartThemeEmColor);\n  word-break: break-word;\n}\n\n.script-meta {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  font-size: 12px;\n}\n\n.script-status {\n  color: #888;\n  padding: 2px 6px;\n  border-radius: 3px;\n  background: rgba(0, 0, 0, 0.1);\n}\n\n.script-status.enabled {\n  color: #4caf50;\n  background: rgba(76, 175, 80, 0.1);\n}\n\n.script-buttons-count {\n  display: flex;\n  align-items: center;\n  gap: 2px;\n  color: #666;\n}\n\n.script-actions {\n  display: flex;\n  gap: 6px;\n  align-items: flex-start;\n  flex-shrink: 0;\n}\n\n.toggle-btn,\n.action-btn {\n  background: none;\n  border: 1px solid var(--SmartThemeBorderColor);\n  padding: 6px 8px;\n  border-radius: 4px;\n  cursor: pointer;\n  color: var(--SmartThemeBodyColor);\n  transition: all 0.2s ease;\n  font-size: 12px;\n}\n\n.toggle-btn.enabled {\n  color: #4caf50;\n  border-color: #4caf50;\n}\n\n.action-btn:hover,\n.toggle-btn:hover {\n  background: rgba(255, 255, 255, 0.1);\n}\n\n.action-btn:disabled {\n  opacity: 0.5;\n  cursor: not-allowed;\n}\n\n.run-btn:not(:disabled):hover {\n  color: #4caf50;\n  border-color: #4caf50;\n}\n\n.menu-btn:hover {\n  color: var(--SmartThemeEmColor);\n}\n\n.script-description {\n  font-size: 13px;\n  color: var(--SmartThemeBodyColor);\n  opacity: 0.8;\n  line-height: 1.4;\n  padding: 8px 0;\n  border-bottom: 1px solid rgba(255, 255, 255, 0.05);\n}\n\n.script-preview {\n  background: rgba(0, 0, 0, 0.2);\n  border-radius: 4px;\n  overflow: hidden;\n}\n\n.preview-header {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  padding: 8px 12px;\n  background: rgba(0, 0, 0, 0.2);\n  border-bottom: 1px solid rgba(255, 255, 255, 0.1);\n}\n\n.preview-label {\n  font-size: 12px;\n  color: var(--SmartThemeBodyColor);\n  font-weight: 500;\n}\n\n.preview-close-btn {\n  background: none;\n  border: none;\n  color: #888;\n  cursor: pointer;\n  padding: 2px 4px;\n  font-size: 10px;\n}\n\n.preview-close-btn:hover {\n  color: var(--SmartThemeEmColor);\n}\n\n.preview-code {\n  padding: 12px;\n  margin: 0;\n  font-family: 'Consolas', 'Monaco', 'Courier New', monospace;\n  font-size: 11px;\n  line-height: 1.4;\n  color: #e8e8e8;\n  white-space: pre-wrap;\n  word-break: break-word;\n  max-height: 200px;\n  overflow-y: auto;\n}\n\n.script-footer {\n  display: flex;\n  justify-content: center;\n  padding-top: 4px;\n}\n\n.expand-btn {\n  background: none;\n  border: 1px solid var(--SmartThemeBorderColor);\n  color: var(--SmartThemeBodyColor);\n  padding: 4px 12px;\n  border-radius: 3px;\n  cursor: pointer;\n  font-size: 11px;\n  transition: all 0.2s ease;\n}\n\n.expand-btn:hover {\n  background: rgba(255, 255, 255, 0.1);\n  border-color: var(--SmartThemeEmColor);\n  color: var(--SmartThemeEmColor);\n}\n\n/* 代码滚动条 */\n.preview-code::-webkit-scrollbar {\n  width: 6px;\n}\n\n.preview-code::-webkit-scrollbar-track {\n  background: rgba(0, 0, 0, 0.2);\n}\n\n.preview-code::-webkit-scrollbar-thumb {\n  background: rgba(255, 255, 255, 0.2);\n  border-radius: 3px;\n}\n\n.preview-code::-webkit-scrollbar-thumb:hover {\n  background: rgba(255, 255, 255, 0.3);\n}\n</style>\n"],"sourceRoot":""}]);
